func calLabCellClass(inMonth, isToday, isSelected, highlightWeekend, compact bool) string {
	h := "min-h-12"
	if compact {
		h = "min-h-8"
	}
	base := "flex flex-col items-center justify-start p-1 rounded text-base-content cursor-pointer hover:bg-base-300 " + h
	if !inMonth {
		base += " opacity-30"
	}
	if highlightWeekend {
		base += " bg-base-300/50"
	} else {
		if isSelected {
			base += " bg-primary/20"
		} else {
			base += " bg-base-100"
		}
	}
	if isToday {
		base += " ring-1 ring-primary"
	}
	if isSelected && highlightWeekend {
		base += " ring-2 ring-primary"
	}
	return base
}

